  ('ex_kbwindmill', NULL, 'Kettlebell Windmill', 'Molino con pesa rusa', 'Core', 'Kettlebell', 'Mobility', 3, '8-10', 40, 'Press a kettlebell overhead and hinge sideways toward your front foot, keeping your eyes on the bell.', 'Presiona una pesa rusa sobre la cabeza e inclínate lateralmente hacia el pie delantero, sin perder de vista la pesa.', ARRAY['obliques'], ARRAY['side_delts','hamstrings','lower_back'], NULL, '{"obliques":82,"side_delts":35,"hamstrings":30,"lower_back":25}'::jsonb, 'core', 'Kettlebell Area', TRUE),
  ('ex_birddog', NULL, 'Bird Dog', 'Perro de caza', 'Core', 'Bodyweight', 'Endurance', 3, '10-12', 60, 'On all fours, extend the opposite arm and leg until level with your torso, then switch without rotating your hips.', 'En cuatro puntos, extiende el brazo y la pierna opuestos hasta alinearlos con el torso, luego cambia sin rotar la cadera.', ARRAY['lower_back'], ARRAY['glutes','mid_abs','obliques'], NULL, '{"lower_back":80,"glutes":45,"mid_abs":40,"obliques":30}'::jsonb, 'core', 'Open Floor', TRUE),
  ('ex_standcblcr', NULL, 'Standing Cable Crunch', 'Crunch de pie en polea', 'Core', 'Cable', 'Hypertrophy', 3, '12-15', 90, 'With the rope at head height, crunch down by contracting your abs, keeping your hips fixed.', 'Con la cuerda a la altura de la cabeza, flexiona hacia abajo contrayendo los abdominales, manteniendo la cadera fija.', ARRAY['upper_abs'], ARRAY['mid_abs','obliques'], NULL, '{"upper_abs":85,"mid_abs":55,"obliques":25}'::jsonb, 'core', 'Cable Station', TRUE),
  ('ex_wtsitup', NULL, 'Weighted Sit-Up', 'Abdominal con peso', 'Core', 'Dumbbell', 'Hypertrophy', 3, '10-12', 90, 'Hold a dumbbell against your chest and sit all the way up, curling your torso rather than yanking with your hips.', 'Sujeta una mancuerna contra el pecho y siéntate por completo, enrollando el torso en lugar de tirar con la cadera.', ARRAY['upper_abs'], ARRAY['mid_abs','hip_flexors'], NULL, '{"upper_abs":85,"mid_abs":60,"hip_flexors":35}'::jsonb, 'core', 'Dumbbell Area', TRUE),
  ('ex_zerchersq', NULL, 'Zercher Squat', 'Sentadilla Zercher', 'Legs', 'Barbell', 'Strength', 3, '6-8', 150, 'Cradle the barbell in the crook of your elbows, brace your core, and squat down keeping your torso upright.', 'Sostén la barra en el pliegue de los codos, aprieta el core y baja en sentadilla manteniendo el torso erguido.', ARRAY['quads'], ARRAY['glutes','adductors','upper_back'], NULL, '{"quads":85,"glutes":62,"adductors":45,"upper_back":40}'::jsonb, 'squat', 'Squat Rack', TRUE),
  ('ex_boxsquat', NULL, 'Box Squat', 'Sentadilla al Cajón', 'Legs', 'Barbell', 'Strength', 3, '5', 150, 'Sit back onto a box until your hips are just below parallel, pause, then drive through your heels to stand.', 'Siéntate hacia atrás sobre un cajón hasta que las caderas queden bajo la paralela, haz una pausa y empuja con los talones para subir.', ARRAY['quads','glutes'], ARRAY['hamstrings','lower_back'], NULL, '{"quads":82,"glutes":80,"hamstrings":48,"lower_back":40}'::jsonb, 'squat', 'Squat Rack', TRUE),
  ('ex_lmsquat', NULL, 'Landmine Squat', 'Sentadilla con Landmine', 'Legs', 'Barbell', 'Hypertrophy', 3, '8-12', 90, 'Hold the end of a landmine barbell at chest height and squat down, letting the arc guide you upright and deep.', 'Sujeta el extremo de la barra en landmine a la altura del pecho y baja en sentadilla, dejando que el arco te mantenga erguido y profundo.', ARRAY['quads'], ARRAY['glutes','adductors'], NULL, '{"quads":84,"glutes":58,"adductors":42}'::jsonb, 'squat', 'Squat Rack', TRUE),
  ('ex_heelgobsq', NULL, 'Heels-Elevated Goblet Squat', 'Sentadilla Goblet con Talones Elevados', 'Legs', 'Dumbbell', 'Hypertrophy', 3, '10-15', 90, 'With heels on a small wedge and a dumbbell held at your chest, squat straight down to bias the quads.', 'Con los talones sobre una cuña y una mancuerna en el pecho, baja recto en sentadilla para enfatizar los cuádriceps.', ARRAY['quads'], ARRAY['glutes'], NULL, '{"quads":86,"glutes":50}'::jsonb, 'squat', 'Dumbbell Area', TRUE),
  ('ex_latlunge', NULL, 'Lateral Lunge', 'Zancada Lateral', 'Legs', 'Dumbbell', 'Hypertrophy', 3, '10-12', 90, 'Step wide to one side and sit back into that hip, keeping the trailing leg straight, then push back to center.', 'Da un paso amplio hacia un lado y siéntate sobre esa cadera manteniendo la pierna contraria estirada, luego empuja al centro.', ARRAY['quads'], ARRAY['adductors','glutes'], NULL, '{"quads":80,"adductors":65,"glutes":50}'::jsonb, 'squat', 'Dumbbell Area', TRUE),
  ('ex_dblunge', NULL, 'Dumbbell Lunge', 'Zancada con Mancuernas', 'Legs', 'Dumbbell', 'Hypertrophy', 3, '10-12', 90, 'Hold dumbbells at your sides, step forward into a lunge until both knees bend to 90 degrees, then push back to standing.', 'Sujeta mancuernas a los costados, da un paso al frente en zancada hasta que ambas rodillas formen 90 grados y regresa a la posición inicial.', ARRAY['quads'], ARRAY['glutes','hamstrings'], NULL, '{"quads":82,"glutes":60,"hamstrings":40}'::jsonb, 'squat', 'Dumbbell Area', TRUE),
  ('ex_cossacksq', NULL, 'Cossack Squat', 'Sentadilla Cosaca', 'Legs', 'Bodyweight', 'Mobility', 3, '8-10', 40, 'Shift your weight over one bent leg while extending the other straight to the side, staying low, then transfer to the other side.', 'Desplaza el peso sobre una pierna flexionada mientras extiendes la otra recta hacia el lado, mantente abajo y cambia al otro lado.', ARRAY['quads'], ARRAY['adductors','glutes'], NULL, '{"quads":80,"adductors":62,"glutes":48}'::jsonb, 'squat', 'Open Floor', TRUE),
  ('ex_pistolsq', NULL, 'Pistol Squat', 'Sentadilla Pistol', 'Legs', 'Bodyweight', 'Strength', 3, '5-8', 150, 'Extend one leg forward and squat down on the other until your hamstring meets your calf, then stand without letting the free foot touch.', 'Extiende una pierna al frente y baja en sentadilla sobre la otra hasta que el muslo toque la pantorrilla, luego sube sin apoyar el pie libre.', ARRAY['quads'], ARRAY['glutes','hamstrings'], NULL, '{"quads":85,"glutes":58,"hamstrings":40}'::jsonb, 'squat', 'Open Floor', TRUE),
  ('ex_bbsplitsq', NULL, 'Barbell Split Squat', 'Sentadilla Partida con Barra', 'Legs', 'Barbell', 'Hypertrophy', 3, '8-10', 90, 'With the barbell on your back and feet in a long staggered stance, lower straight down until the back knee nears the floor, then drive up.', 'Con la barra en la espalda y los pies en zancada larga, baja recto hasta que la rodilla trasera casi toque el suelo y empuja hacia arriba.', ARRAY['quads'], ARRAY['glutes','hamstrings'], NULL, '{"quads":84,"glutes":60,"hamstrings":42}'::jsonb, 'squat', 'Squat Rack', TRUE),
  ('ex_sllegext', NULL, 'Single-Leg Leg Extension', 'Extensión de Cuádriceps a Una Pierna', 'Legs', 'Machine', 'Hypertrophy', 3, '12-15', 90, 'Extend one leg at a time against the pad, squeezing the quad hard at the top before lowering under control.', 'Extiende una pierna a la vez contra el rodillo, aprieta fuerte el cuádriceps arriba y baja de forma controlada.', ARRAY['quads'], ARRAY[]::text[], NULL, '{"quads":90}'::jsonb, 'isolation_push', 'Leg Extension', TRUE),
  ('ex_standlegcurl', NULL, 'Standing Leg Curl', 'Curl Femoral de Pie', 'Legs', 'Machine', 'Hypertrophy', 3, '12-15', 90, 'Standing on one leg, curl the other heel toward your glute against the pad, then lower slowly.', 'De pie sobre una pierna, flexiona el talón contrario hacia el glúteo contra el rodillo y baja lentamente.', ARRAY['hamstrings'], ARRAY['calves'], NULL, '{"hamstrings":88,"calves":25}'::jsonb, 'isolation_pull', 'Leg Curl', TRUE),
  ('ex_revnordic', NULL, 'Reverse Nordic Curl', 'Curl Nórdico Inverso', 'Legs', 'Bodyweight', 'Hypertrophy', 3, '8-12', 90, 'Kneeling tall, lean your torso back as one unit while resisting with the quads, then pull yourself upright.', 'Arrodillado y erguido, inclina el torso hacia atrás como un bloque resistiendo con los cuádriceps y vuelve a subir.', ARRAY['quads'], ARRAY['hip_flexors'], NULL, '{"quads":85,"hip_flexors":45}'::jsonb, 'isolation_push', 'Open Floor', TRUE),
  ('ex_spanishsq', NULL, 'Spanish Squat', 'Sentadilla Española', 'Legs', 'Resistance Band', 'Hypertrophy', 3, '12-15', 90, 'Loop a band behind your knees anchored in front, sit straight down keeping your shins vertical to load the quads.', 'Coloca una banda tras las rodillas anclada al frente, baja recto manteniendo las tibias verticales para cargar los cuádriceps.', ARRAY['quads'], ARRAY[]::text[], NULL, '{"quads":84}'::jsonb, 'squat', 'Resistance Bands', TRUE),
  ('ex_smithlunge', NULL, 'Smith Machine Lunge', 'Zancada en Máquina Smith', 'Legs', 'Smith Machine', 'Hypertrophy', 3, '10-12', 90, 'With the bar on your back and one foot forward, lower into a lunge along the fixed bar path, then press back up.', 'Con la barra en la espalda y un pie adelante, baja en zancada siguiendo el recorrido fijo de la barra y sube.', ARRAY['quads'], ARRAY['glutes'], NULL, '{"quads":82,"glutes":60}'::jsonb, 'squat', 'Smith Machine', TRUE),
  ('ex_slrdl', NULL, 'Single-Leg Romanian Deadlift', 'Peso Muerto Rumano a Una Pierna', 'Legs', 'Dumbbell', 'Hypertrophy', 3, '8-12', 90, 'Balancing on one leg, hinge at the hip and lower the dumbbell along your shin while the free leg extends behind, then return.', 'En equilibrio sobre una pierna, haz bisagra de cadera y baja la mancuerna por la espinilla mientras la pierna libre se extiende atrás, y regresa.', ARRAY['hamstrings'], ARRAY['glutes','lower_back'], NULL, '{"hamstrings":85,"glutes":65,"lower_back":38}'::jsonb, 'hinge', 'Dumbbell Area', TRUE),
  ('ex_bbglutebr', NULL, 'Barbell Glute Bridge', 'Puente de Glúteos con Barra', 'Glutes', 'Barbell', 'Hypertrophy', 3, '10-12', 90, 'Lying on the floor with a barbell over your hips, drive through your heels to lift your hips until your body forms a straight line, squeezing the glutes.', 'Tumbado en el suelo con una barra sobre las caderas, empuja con los talones para elevar la cadera hasta alinear el cuerpo, apretando los glúteos.', ARRAY['glutes'], ARRAY['hamstrings'], NULL, '{"glutes":88,"hamstrings":48}'::jsonb, 'hinge', 'Barbell Platform', TRUE),
  ('ex_slglutebr', NULL, 'Single-Leg Glute Bridge', 'Puente de Glúteos a Una Pierna', 'Glutes', 'Bodyweight', 'Hypertrophy', 3, '12-15', 90, 'With one foot planted and the other leg extended, drive through the heel to raise your hips and squeeze the glute at the top.', 'Con un pie apoyado y la otra pierna extendida, empuja con el talón para elevar la cadera y aprieta el glúteo arriba.', ARRAY['glutes'], ARRAY['hamstrings'], NULL, '{"glutes":85,"hamstrings":45}'::jsonb, 'hinge', 'Open Floor', TRUE),
  ('ex_bstanceht', NULL, 'B-Stance Hip Thrust', 'Empuje de Cadera en Apoyo Escalonado', 'Glutes', 'Dumbbell', 'Hypertrophy', 3, '10-12', 90, 'With your back on a bench and one foot slightly forward as a kickstand, drive mostly through the working heel to thrust the hips up.', 'Con la espalda en un banco y un pie ligeramente adelante como apoyo, empuja sobre todo con el talón de trabajo para elevar la cadera.', ARRAY['glutes'], ARRAY['hamstrings'], NULL, '{"glutes":87,"hamstrings":45}'::jsonb, 'hinge', 'Dumbbell Area', TRUE),
  ('ex_revhyper', NULL, 'Reverse Hyperextension', 'Hiperextensión Inversa', 'Glutes', 'Machine', 'Hypertrophy', 3, '12-15', 90, 'Lying face down on the machine with your hips at the edge, raise your legs behind you by squeezing the glutes, then lower under control.', 'Tumbado boca abajo en la máquina con la cadera al borde, eleva las piernas hacia atrás apretando los glúteos y baja de forma controlada.', ARRAY['glutes'], ARRAY['hamstrings','lower_back'], NULL, '{"glutes":82,"hamstrings":58,"lower_back":45}'::jsonb, 'hinge', 'Back Extension', TRUE),
  ('ex_bandabduct', NULL, 'Banded Hip Abduction', 'Abducción de Cadera con Banda', 'Glutes', 'Resistance Band', 'Endurance', 3, '15-20', 60, 'With a loop band around your knees, seated or standing, push your knees apart against the band and control the return.', 'Con una banda alrededor de las rodillas, sentado o de pie, separa las rodillas contra la banda y controla el regreso.', ARRAY['glute_med'], ARRAY['glutes'], NULL, '{"glute_med":85,"glutes":50}'::jsonb, 'isolation_pull', 'Resistance Bands', TRUE),
