  ('ex_clamshell', NULL, 'Clamshell', 'Almeja', 'Glutes', 'Resistance Band', 'Endurance', 2, '15-20', 60, 'Lying on your side with knees bent and a band around your thighs, open the top knee like a clam while keeping your feet together.', 'Tumbado de lado con las rodillas flexionadas y una banda en los muslos, abre la rodilla superior como una almeja manteniendo los pies juntos.', ARRAY['glute_med'], ARRAY['glutes'], NULL, '{"glute_med":84,"glutes":45}'::jsonb, 'isolation_pull', 'Resistance Bands', TRUE),
  ('ex_curtsylunge', NULL, 'Curtsy Lunge', 'Zancada de Reverencia', 'Glutes', 'Dumbbell', 'Hypertrophy', 3, '10-12', 90, 'Step one leg diagonally behind the other and lower into a curtsy, then drive back up to load the side glute.', 'Cruza una pierna en diagonal por detrás de la otra y baja en reverencia, luego sube para trabajar el glúteo lateral.', ARRAY['glutes'], ARRAY['glute_med','quads'], NULL, '{"glutes":80,"glute_med":62,"quads":55}'::jsonb, 'squat', 'Dumbbell Area', TRUE),
  ('ex_smithcalf', NULL, 'Smith Machine Calf Raise', 'Elevación de Talones en Máquina Smith', 'Calves', 'Smith Machine', 'Hypertrophy', 4, '12-15', 90, 'With the balls of your feet on a block under the bar, rise onto your toes as high as possible, then lower for a deep stretch.', 'Con la punta de los pies sobre un escalón bajo la barra, elévate sobre los dedos lo más alto posible y baja buscando un estiramiento profundo.', ARRAY['calves'], ARRAY['soleus'], NULL, '{"calves":88,"soleus":45}'::jsonb, 'isolation_push', 'Smith Machine', TRUE),
  ('ex_dbcalf', NULL, 'Dumbbell Standing Calf Raise', 'Elevación de Talones de Pie con Mancuernas', 'Calves', 'Dumbbell', 'Hypertrophy', 4, '15-20', 90, 'Holding dumbbells at your sides with your toes on a block, press up onto your toes and squeeze the calves before lowering fully.', 'Con mancuernas a los costados y la punta de los pies en un escalón, elévate sobre los dedos y aprieta los gemelos antes de bajar del todo.', ARRAY['calves'], ARRAY['soleus'], NULL, '{"calves":88,"soleus":42}'::jsonb, 'isolation_push', 'Dumbbell Area', TRUE),
  ('ex_hackcalf', NULL, 'Hack Squat Calf Raise', 'Elevación de Talones en Hack', 'Calves', 'Machine', 'Hypertrophy', 4, '12-15', 90, 'Positioned in the hack squat with the balls of your feet on the platform edge, extend your ankles to press up, then lower for a stretch.', 'Colocado en la hack con la punta de los pies en el borde de la plataforma, extiende los tobillos para subir y baja buscando estiramiento.', ARRAY['calves'], ARRAY['soleus'], NULL, '{"calves":88,"soleus":45}'::jsonb, 'isolation_push', 'Hack Squat', TRUE),
  ('ex_bandcalf', NULL, 'Banded Calf Raise', 'Elevación de Talones con Banda', 'Calves', 'Resistance Band', 'Endurance', 3, '15-20', 60, 'Stand on a band held taut in your hands and rise onto your toes against the added tension, controlling the descent.', 'Párate sobre una banda tensada con las manos y elévate sobre los dedos contra la resistencia, controlando la bajada.', ARRAY['calves'], ARRAY['soleus'], NULL, '{"calves":85,"soleus":42}'::jsonb, 'isolation_push', 'Resistance Bands', TRUE),
  ('ex_seateddbcalf', NULL, 'Seated Dumbbell Calf Raise', 'Elevación de Talones Sentado con Mancuerna', 'Calves', 'Dumbbell', 'Hypertrophy', 4, '15-20', 90, 'Seated with dumbbells resting on your knees and your toes on a block, raise your heels by contracting the soleus, then lower slowly.', 'Sentado con mancuernas sobre las rodillas y la punta de los pies en un escalón, eleva los talones contrayendo el sóleo y baja lentamente.', ARRAY['soleus'], ARRAY['calves'], NULL, '{"soleus":85,"calves":50}'::jsonb, 'isolation_push', 'Dumbbell Area', TRUE),
  ('ex_dbsnatch', NULL, 'Dumbbell Snatch', 'Arrancada con Mancuerna', 'Full Body', 'Dumbbell', 'Power', 4, '5', 150, 'Explosively pull a single dumbbell from between your feet to overhead in one motion, extending your hips, knees, and ankles.', 'Tira explosivamente de una mancuerna desde el suelo hasta encima de la cabeza en un solo movimiento, extendiendo cadera, rodillas y tobillos.', ARRAY['glutes'], ARRAY['hamstrings','side_delts','traps','quads'], NULL, '{"glutes":82,"hamstrings":58,"side_delts":55,"traps":50,"quads":45}'::jsonb, 'hinge', 'Dumbbell Area', TRUE),
  ('ex_kbsnatch', NULL, 'Kettlebell Snatch', 'Arrancada con Kettlebell', 'Full Body', 'Kettlebell', 'Power', 4, '6-8', 150, 'Hike the kettlebell back, then snap your hips forward to launch it overhead, punching your hand through at lockout.', 'Balancea la kettlebell atrás y proyecta la cadera al frente para lanzarla por encima de la cabeza, atravesando la mano en el bloqueo.', ARRAY['glutes'], ARRAY['hamstrings','side_delts','traps','lower_back'], NULL, '{"glutes":82,"hamstrings":58,"side_delts":52,"traps":48,"lower_back":40}'::jsonb, 'hinge', 'Kettlebell Area', TRUE),
  ('ex_kbclean', NULL, 'Kettlebell Clean', 'Cargada con Kettlebell', 'Full Body', 'Kettlebell', 'Power', 3, '6-8', 150, 'Drive the kettlebell up from a hip hinge and rotate it around to land softly in the rack position against your forearm.', 'Impulsa la kettlebell desde una bisagra de cadera y gírala para recibirla suavemente en posición de rack contra el antebrazo.', ARRAY['glutes'], ARRAY['hamstrings','traps','biceps','forearms'], NULL, '{"glutes":80,"hamstrings":55,"traps":48,"biceps":35,"forearms":40}'::jsonb, 'hinge', 'Kettlebell Area', TRUE),
  ('ex_devilspress', NULL, 'Devil''s Press', 'Devil Press', 'Full Body', 'Dumbbell', 'Power', 3, '8-10', 150, 'From a burpee over two dumbbells, swing them from the floor to overhead in one continuous snatch as you stand.', 'Desde un burpee sobre dos mancuernas, impúlsalas del suelo hasta encima de la cabeza en un solo movimiento al ponerte de pie.', ARRAY['glutes'], ARRAY['front_delts','quads','hamstrings','mid_chest'], NULL, '{"glutes":80,"front_delts":65,"quads":55,"hamstrings":50,"mid_chest":40}'::jsonb, 'hinge', 'Dumbbell Area', TRUE),
  ('ex_bearcrawl', NULL, 'Bear Crawl', 'Caminata del Oso', 'Full Body', 'Bodyweight', 'Endurance', 3, '30-45 sec', 60, 'On your hands and toes with knees hovering just off the floor, crawl forward moving opposite hand and foot while keeping your hips low and stable.', 'Sobre manos y puntas de los pies con las rodillas justo sobre el suelo, avanza moviendo mano y pie opuestos manteniendo la cadera baja y estable.', ARRAY['upper_abs'], ARRAY['obliques','front_delts','quads','triceps'], NULL, '{"upper_abs":80,"obliques":58,"front_delts":55,"quads":48,"triceps":42}'::jsonb, 'core', 'Open Floor', TRUE),
  ('ex_kbohcarry', NULL, 'Kettlebell Overhead Carry', 'Caminata con Kettlebell Sobre la Cabeza', 'Full Body', 'Kettlebell', 'Endurance', 3, '40-60 sec', 60, 'Press a kettlebell overhead and walk with a locked elbow, keeping your ribs down and core braced the entire distance.', 'Presiona una kettlebell sobre la cabeza y camina con el codo bloqueado, manteniendo las costillas abajo y el core firme toda la distancia.', ARRAY['side_delts'], ARRAY['upper_abs','obliques','traps','forearms'], NULL, '{"side_delts":82,"upper_abs":60,"obliques":52,"traps":48,"forearms":45}'::jsonb, 'carry', 'Kettlebell Area', TRUE),
  ('ex_assaultbike', NULL, 'Assault Bike', 'Bicicleta de Asalto', 'Cardio', 'Cardio Machine', 'Cardio', 1, '15 min', 45, 'Push and pull the handles while driving the pedals, keeping a steady hard pace or alternating sprint and recovery intervals.', 'Empuja y tira de las manijas mientras pedaleas, manteniendo un ritmo fuerte y constante o alternando intervalos de sprint y recuperación.', ARRAY['quads'], ARRAY['hamstrings','front_delts','lats'], NULL, '{"quads":80,"hamstrings":52,"front_delts":45,"lats":42}'::jsonb, 'cardio', 'Stationary Bike', TRUE),
