-- ============================================================
-- 0622 — exercises: DB becomes source of truth (+ library expansion)
-- ============================================================
-- exercises.id is TEXT and every routine_exercises/personal_records/etc FKs to
-- it, so exercises.js was really an in-memory MIRROR of the global library.
-- This makes the DB authoritative and idempotently upserts ALL 305 exercises
-- (original library refreshed + the 132 new ones inserted) so generated routines
-- that reference the new ids satisfy the foreign key. Adds the fields the
-- generator + equipment-QR feature need (muscle_scores, movement_pattern, station).
-- Vocab already covered by existing enums. Additive + idempotent.
-- ============================================================

ALTER TABLE exercises ADD COLUMN IF NOT EXISTS muscle_scores    jsonb;
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS movement_pattern text;
ALTER TABLE exercises ADD COLUMN IF NOT EXISTS station          text;

ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name, name_es = EXCLUDED.name_es, muscle_group = EXCLUDED.muscle_group,
  equipment = EXCLUDED.equipment, category = EXCLUDED.category, default_sets = EXCLUDED.default_sets,
  default_reps = EXCLUDED.default_reps, rest_seconds = EXCLUDED.rest_seconds, instructions = EXCLUDED.instructions,
  instructions_es = EXCLUDED.instructions_es, primary_regions = EXCLUDED.primary_regions,
  secondary_regions = EXCLUDED.secondary_regions, video_url = COALESCE(EXCLUDED.video_url, exercises.video_url),
  muscle_scores = EXCLUDED.muscle_scores, movement_pattern = EXCLUDED.movement_pattern,
  station = EXCLUDED.station, is_active = TRUE;

CREATE INDEX IF NOT EXISTS idx_exercises_station ON exercises(station) WHERE is_active = TRUE AND station IS NOT NULL;
